import React, { useState, useEffect, useMemo } from 'react';
import { ViewState, FineEntry, User, TimeFilter, UserSettings, Player, PresetFine, RoleDefinition } from './types';
import { DEFAULT_PLAYERS, PRESET_FINES as DEFAULT_PRESET_FINES, DEFAULT_ROLES } from './constants';
import { AddFineView } from './components/AddFineView';
import { StatsView } from './components/StatsView';
import { PlayerProfileView } from './components/PlayerProfileView';
import { LoginView } from './components/LoginView';
import { FineListView } from './components/FineListView';
import { NotificationsView } from './components/NotificationsView';
import { SettingsModal } from './components/SettingsModal';
import { FineDetailView } from './components/FineDetailView';
import { SearchModal } from './components/SearchModal';
import { cloudSave, cloudFetchAll, cloudDelete, cloudFetchOne } from './services/supabaseService';
import { PlusCircle, BarChart3, Shield, Table, LogOut, Bell, Settings, Search, Loader2, CheckCircle2, Cloud } from 'lucide-react';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [view, setView] = useState<ViewState>('login');
  const [isLoading, setIsLoading] = useState(true);
  const [isSyncing, setIsSyncing] = useState(false);
  const [showSuccessToast, setShowSuccessToast] = useState<string | null>(null);

  const [players, setPlayers] = useState<Player[]>(DEFAULT_PLAYERS);
  const [presetFines, setPresetFines] = useState<PresetFine[]>(DEFAULT_PRESET_FINES);
  const [fines, setFines] = useState<FineEntry[]>([]);
  const [settings, setSettings] = useState<Record<string, UserSettings>>({});
  const [roles, setRoles] = useState<RoleDefinition[]>(DEFAULT_ROLES);

  const [selectedPlayerId, setSelectedPlayerId] = useState<string | null>(null);
  const [selectedFineId, setSelectedFineId] = useState<string | null>(null);
  const [filter, setFilter] = useState<TimeFilter>('all');
  const [showSettingsModal, setShowSettingsModal] = useState(false);
  const [showSearchModal, setShowSearchModal] = useState(false);

  const loadAllCloudData = async () => {
    setIsSyncing(true);
    try {
        const [cloudFines, cloudPlayers, cloudPresets, cloudRoles, cloudSettings] = await Promise.all([
            cloudFetchAll('fine'),
            cloudFetchAll('player'),
            cloudFetchAll('preset'),
            cloudFetchAll('role'),
            cloudFetchAll('settings')
        ]);

        if (cloudFines.length > 0) setFines(cloudFines);
        if (cloudPlayers.length > 0) setPlayers(cloudPlayers);
        if (cloudPresets.length > 0) setPresetFines(cloudPresets);
        if (cloudRoles.length > 0) setRoles(cloudRoles);

        const settingsDict: Record<string, UserSettings> = {};
        cloudSettings.forEach((s: any) => { if (s.userId) settingsDict[s.userId] = s; });
        if (Object.keys(settingsDict).length > 0) setSettings(settingsDict);

    } catch (e) {
        console.error("Cloud Load Error", e);
    } finally {
        setIsSyncing(false);
        setIsLoading(false);
    }
  };

  useEffect(() => { loadAllCloudData(); }, []);

  const saveFine = async (fine: FineEntry) => {
      setFines(prev => {
          const exists = prev.find(f => f.id === fine.id);
          if (exists) return prev.map(f => f.id === fine.id ? fine : f);
          return [...prev, fine];
      });
      await cloudSave('fine', fine.id, fine);
      setShowSuccessToast("Sky-lagret!");
      setTimeout(() => setShowSuccessToast(null), 2000);
  };

  const deleteFine = async (id: string) => {
      setFines(prev => prev.filter(f => f.id !== id));
      await cloudDelete('fine', id);
  };

  const handleUpdateSettings = async (playerId: string, newSettings: UserSettings) => {
    setIsSyncing(true);
    await cloudSave('settings', playerId, { ...newSettings, userId: playerId });
    setSettings(prev => ({ ...prev, [playerId]: newSettings }));
    setShowSuccessToast("Lagret!");
    setTimeout(() => setShowSuccessToast(null), 2000);
    setIsSyncing(false);
    setShowSettingsModal(false);
  };

  const handleUpdatePassword = async (newPassword: string) => {
    if (!user) return;
    setIsSyncing(true);
    await cloudSave('auth', user.id, { password: newPassword });
    setShowSuccessToast("Passord oppdatert!");
    setTimeout(() => setShowSuccessToast(null), 2000);
    setIsSyncing(false);
  };

  // Auth logic: Verify password against Supabase or default '1234'
  const verifyPassword = async (userId: string, input: string): Promise<boolean> => {
    try {
        const authData = await cloudFetchOne('auth', userId);
        const storedPassword = authData?.password || '1234';
        return input === storedPassword;
    } catch (e) {
        console.error("Auth error", e);
        return false;
    }
  };

  const handleLogout = () => { setUser(null); setView('login'); setSelectedPlayerId(null); };

  const headerStats = useMemo(() => {
    const targetFines = user?.role === 'admin' ? fines : fines.filter(f => f.playerId === user?.id);
    return {
      debt: targetFines.filter(f => f.status === 'unpaid').reduce((a, b) => a + b.amount, 0),
      paid: targetFines.filter(f => f.status === 'paid').reduce((a, b) => a + b.amount, 0)
    };
  }, [user, fines]);

  if (isLoading) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-slate-50">
        <Loader2 className="w-10 h-10 animate-spin text-blue-600 mb-4" />
        <p className="text-slate-500 font-bold">Laster NHHI Botkassa...</p>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-slate-50 text-slate-900 font-sans pb-24">
      {showSuccessToast && (
        <div className="fixed top-6 left-1/2 -translate-x-1/2 z-[100] bg-slate-900 text-white px-6 py-3 rounded-full shadow-2xl flex items-center gap-2 animate-in fade-in slide-in-from-top-4">
          <CheckCircle2 size={16} className="text-green-400" />
          <span className="text-xs font-bold uppercase tracking-wider">{showSuccessToast}</span>
        </div>
      )}

      {user && (
        <header className="bg-blue-900 text-white pt-10 pb-20 px-6 rounded-b-[3rem] shadow-xl relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-10 pointer-events-none -rotate-12"><Shield size={220} /></div>
            <div className="relative z-10">
                <div className="flex justify-between items-start mb-6">
                    <div>
                        <div className="flex items-center space-x-2 mb-2">
                            <button onClick={() => setShowSettingsModal(true)} className="p-2 bg-blue-800 rounded-xl hover:bg-blue-700"><Settings size={16} /></button>
                            <span className="px-3 py-1 rounded-full text-[10px] font-black uppercase bg-white/10 border border-white/10 backdrop-blur-sm">
                              {user.role === 'admin' ? 'Botsjef' : 'Spiller'}
                            </span>
                            <div className={`p-2 rounded-full transition-colors ${isSyncing ? 'bg-blue-400' : 'bg-green-500/20 text-green-400'}`}>
                                <Cloud size={14} className={isSyncing ? 'animate-pulse' : ''} />
                            </div>
                        </div>
                        <h1 className="text-2xl font-black tracking-tight">NHHI FC</h1>
                        <p className="text-blue-200 text-xs font-medium opacity-80">{user.name}</p>
                    </div>
                    <div className="flex items-center space-x-2">
                        <button onClick={() => setShowSearchModal(true)} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700"><Search size={20} /></button>
                        <button onClick={() => setView('notifications')} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700"><Bell size={20} /></button>
                        <button onClick={handleLogout} className="p-2.5 bg-blue-800 rounded-2xl hover:bg-blue-700"><LogOut size={20} /></button>
                    </div>
                </div>
                <div className="grid grid-cols-2 gap-4">
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-blue-300 text-[10px] font-black uppercase mb-1 tracking-widest">Gjeld</div>
                        <div className="text-2xl font-black">{headerStats.debt.toLocaleString()} kr</div>
                    </div>
                    <div className="bg-white/5 backdrop-blur-md rounded-3xl p-5 border border-white/10 text-center">
                        <div className="text-green-300 text-[10px] font-black uppercase mb-1 tracking-widest">Betalt</div>
                        <div className="text-2xl font-black">{headerStats.paid.toLocaleString()} kr</div>
                    </div>
                </div>
            </div>
        </header>
      )}

      <main className={`px-4 max-w-lg mx-auto ${user ? '-mt-10 relative z-20' : ''}`}>
        {!user ? (
            <LoginView 
                onLogin={(u) => { setUser(u); if(u.role === 'admin') setView('overview'); else { setSelectedPlayerId(u.id); setView('player'); } }} 
                onVerifyPassword={verifyPassword}
                players={players} 
            />
        ) : (
            view === 'add' ? <AddFineView onAddFine={saveFine} players={players} presetFines={presetFines} /> :
            view === 'overview' ? <StatsView fines={fines} players={players} onSelectPlayer={(id) => { setSelectedPlayerId(id); setView('player'); }} currentFilter={filter} onFilterChange={setFilter} currentUserRole={user.role} /> :
            view === 'list' ? <FineListView fines={fines} players={players} currentFilter={filter} onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} /> :
            view === 'notifications' ? <NotificationsView user={user} fines={fines} players={players} /> :
            view === 'fine_detail' ? <FineDetailView fine={fines.find(f => f.id === selectedFineId)!} player={players.find(p => p.id === fines.find(f => f.id === selectedFineId)?.playerId)!} currentUser={user} presetFines={presetFines} onBack={() => setView('list')} onGoToProfile={(id) => { setSelectedPlayerId(id); setView('player'); }} onAddComment={(fid, t) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, comments: [...(f.comments || []), {id: crypto.randomUUID(), userId: user.id, userName: user.name, text: t, timestamp: Date.now()}]}) }} onDeleteComment={(fid, cid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, comments: (f.comments || []).filter(c => c.id !== cid)}) }} onToggleFineReaction={(fid, e) => { const f = fines.find(x => x.id === fid); if(f) { const r = f.reactions || []; const i = r.findIndex(x => x.userId === user.id && x.emoji === e); saveFine({...f, reactions: i > -1 ? r.filter((_, idx) => idx !== i) : [...r, {emoji: e, userId: user.id}]}) } }} onToggleCommentReaction={(fid, cid, e) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, comments: (f.comments || []).map(c => { if(c.id === cid) { const r = c.reactions || []; const i = r.findIndex(x => x.userId === user.id && x.emoji === e); return {...c, reactions: i > -1 ? r.filter((_, idx) => idx !== i) : [...r, {emoji: e, userId: user.id}]}; } return c; })}) }} onUpdateFine={saveFine} onDeleteFine={deleteFine} onAdminPay={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, status: 'paid', payRequest: undefined}) }} /> :
            view === 'player' ? <PlayerProfileView player={players.find(p => p.id === (selectedPlayerId || user.id))!} currentUserRole={user.role} isOwnProfile={user.id === (selectedPlayerId || user.id)} fines={fines.filter(f => f.playerId === (selectedPlayerId || user.id))} settings={settings[selectedPlayerId || user.id] || { pushEnabled: false }} presetFines={presetFines} roles={roles} onUpdateSettings={handleUpdateSettings} onBack={() => user.role === 'admin' ? setView('overview') : setView('list')} onUpdateFine={saveFine} onDeleteFine={deleteFine} onSubmitComplaint={(fid, r) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, complaint: {reason: r, status: 'pending', date: new Date().toISOString()}}) }} onPayRequest={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, payRequest: {status: 'pending', date: new Date().toISOString()}}) }} onAdminPay={(fid) => { const f = fines.find(x => x.id === fid); if(f) saveFine({...f, status: 'paid', payRequest: undefined}) }} onSelectFine={(id) => { setSelectedFineId(id); setView('fine_detail'); }} /> : null
        )}
      </main>

      {user && (
        <nav className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-2xl border-t border-slate-200 pb-safe pt-2 z-50">
            <div className="flex justify-around items-center max-w-lg mx-auto h-16 px-4">
              {user.role === 'admin' && <button onClick={() => setView('add')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'add' ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'text-slate-400 hover:bg-slate-50'}`}><PlusCircle size={22} /><span className="text-[10px] font-black mt-1 uppercase">Gi Bot</span></button>}
              <button onClick={() => setView('overview')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'overview' ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'text-slate-400 hover:bg-slate-50'}`}><BarChart3 size={22} /><span className="text-[10px] font-black mt-1 uppercase">Oversikt</span></button>
              <button onClick={() => setView('list')} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'list' ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'text-slate-400 hover:bg-slate-50'}`}><Table size={22} /><span className="text-[10px] font-black mt-1 uppercase">Liste</span></button>
              <button onClick={() => { setSelectedPlayerId(user.id); setView('player'); }} className={`flex flex-col items-center justify-center w-16 h-16 rounded-2xl transition-all ${view === 'player' && selectedPlayerId === user.id ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'text-slate-400 hover:bg-slate-50'}`}><Shield size={22} /><span className="text-[10px] font-black mt-1 uppercase">Profil</span></button>
            </div>
        </nav>
      )}

      {showSearchModal && <SearchModal players={players} onSelect={(id) => { setSelectedPlayerId(id); setView('player'); setShowSearchModal(false); }} onClose={() => setShowSearchModal(false)} />}

      {showSettingsModal && user && (
        <SettingsModal 
          currentUser={user} 
          settings={settings[user.id] || { pushEnabled: false }} 
          hasPasswordSet={false} // Deprecated prop in this context, logic moved inside
          players={players} 
          presetFines={presetFines} 
          roles={roles} 
          onSave={(updatedSettings, newPassword) => {
              handleUpdateSettings(user.id, updatedSettings);
              if (newPassword) handleUpdatePassword(newPassword);
          }} 
          onCancel={() => setShowSettingsModal(false)} 
          onImportData={(d) => { if(d.fines) setFines(d.fines); if(d.players) setPlayers(d.players); }} 
          exportData={{fines, players}} 
        />
      )}
    </div>
  );
};
export default App;

import React, { useState, useRef, useEffect } from 'react';
import { Player, User } from '../types';
import { User as UserIcon, Shield, Search, Lock, ChevronLeft, ArrowRight, Loader2, AlertCircle } from 'lucide-react';
import { Button } from './Button';

interface LoginViewProps {
  onLogin: (user: User) => void;
  onVerifyPassword: (userId: string, input: string) => Promise<boolean>;
  players: Player[];
}

export const LoginView: React.FC<LoginViewProps> = ({ onLogin, onVerifyPassword, players }) => {
  const [query, setQuery] = useState('');
  const [selectedPlayer, setSelectedPlayer] = useState<Player | null>(null);
  const [password, setPassword] = useState('');
  const [isVerifying, setIsVerifying] = useState(false);
  const [error, setError] = useState(false);
  const passwordInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    if (selectedPlayer && passwordInputRef.current) {
        passwordInputRef.current.focus();
    }
  }, [selectedPlayer]);

  const filteredPlayers = players.filter(p => 
    p.name.toLowerCase().includes(query.toLowerCase())
  );

  const handlePlayerClick = (player: Player) => {
      setSelectedPlayer(player);
      setPassword('');
      setError(false);
  };

  const handlePasswordSubmit = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!selectedPlayer) return;

      setIsVerifying(true);
      setError(false);

      const isValid = await onVerifyPassword(selectedPlayer.id, password);

      setIsVerifying(false);

      if (isValid) {
          onLogin({ 
            id: selectedPlayer.id, 
            name: selectedPlayer.name, 
            role: selectedPlayer.systemRole 
          });
      } else {
          setError(true);
          setPassword('');
      }
  };

  if (selectedPlayer) {
      return (
        <div className="flex flex-col items-center justify-center min-h-screen px-4 py-12">
             <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl w-full max-w-sm text-center border border-slate-100 animate-in fade-in slide-in-from-right-4 duration-300">
                <button 
                    onClick={() => setSelectedPlayer(null)}
                    className="absolute top-8 left-8 p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-50 rounded-full transition-colors"
                >
                    <ChevronLeft size={24} />
                </button>

                <div className="w-20 h-20 bg-blue-50 rounded-full flex items-center justify-center mx-auto mb-4 text-blue-600 shadow-sm">
                     <UserIcon size={32} />
                </div>

                <h2 className="text-xl font-bold text-slate-900 mb-1">{selectedPlayer.name}</h2>
                <p className="text-slate-500 text-sm mb-8">Skriv inn passord for å logge inn</p>

                <form onSubmit={handlePasswordSubmit} className="space-y-4">
                    <div className="relative">
                        <Lock className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
                        <input
                            ref={passwordInputRef}
                            type="password"
                            value={password}
                            onChange={(e) => {
                                setPassword(e.target.value);
                                if(error) setError(false);
                            }}
                            placeholder="Passord"
                            className={`w-full pl-9 pr-4 py-3 bg-slate-50 border rounded-xl focus:ring-2 outline-none text-slate-900 transition-all ${
                                error 
                                ? 'border-red-300 focus:ring-red-200' 
                                : 'border-slate-200 focus:ring-blue-500'
                            }`}
                        />
                    </div>

                    {error && (
                        <div className="flex items-center justify-center text-xs text-red-600 font-medium animate-in fade-in slide-in-from-top-1">
                            <AlertCircle size={12} className="mr-1" />
                            Feil passord. Prøv "1234" hvis du har glemt det.
                        </div>
                    )}

                    <Button type="submit" fullWidth disabled={isVerifying || !password}>
                        {isVerifying ? (
                            <Loader2 className="animate-spin w-5 h-5" />
                        ) : (
                            <>
                                Logg inn <ArrowRight size={16} className="ml-2" />
                            </>
                        )}
                    </Button>
                </form>
             </div>
        </div>
      );
  }

  return (
    <div className="flex flex-col items-center justify-center min-h-screen px-4 py-12">
      <div className="bg-white p-8 rounded-[2.5rem] shadow-2xl w-full max-w-sm text-center border border-slate-100 animate-in fade-in zoom-in duration-300 relative">

        <div className="bg-blue-600 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6 text-white shadow-lg rotate-3">
          <Shield size={30} />
        </div>

        <h1 className="text-2xl font-black text-slate-900 mb-2">NHHI FC</h1>
        <p className="text-slate-400 text-sm mb-8 font-medium">Hvem er du?</p>

        <div className="relative mb-6">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
          <input 
            type="text"
            placeholder="Søk navn..."
            value={query}
            onChange={(e) => setQuery(e.target.value)}
            className="w-full pl-9 pr-4 py-3 bg-slate-50 border border-slate-200 rounded-xl focus:ring-2 focus:ring-blue-500 outline-none text-slate-900"
          />
        </div>

        <div className="space-y-2 max-h-[40vh] overflow-y-auto pr-2 no-scrollbar">
          {filteredPlayers.map(player => (
            <button
              key={player.id}
              onClick={() => handlePlayerClick(player)}
              className="w-full flex items-center p-3 hover:bg-blue-50 border border-slate-100 rounded-2xl transition-all group active:scale-95"
            >
              <div className="w-10 h-10 rounded-full bg-slate-100 flex items-center justify-center text-slate-500 mr-3 group-hover:bg-blue-100 group-hover:text-blue-600 transition-colors">
                <UserIcon size={16} />
              </div>
              <div className="text-left">
                <div className="font-bold text-slate-800 text-sm">{player.name}</div>
                <div className="text-[10px] text-slate-400 uppercase font-black tracking-widest">
                  {player.customRole || player.position || 'Spiller'}
                </div>
              </div>
            </button>
          ))}
          {filteredPlayers.length === 0 && (
            <p className="text-slate-400 text-xs py-4">Ingen spillere funnet</p>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Button } from './Button';
import { UserSettings, User, Player, PresetFine, RoleDefinition } from '../types';
import { X, Smartphone, Bell, BellOff, Tag, Mail, Trash2, Search, AlertCircle, BadgePlus, Download, Upload, Copy, Lock, KeyRound } from 'lucide-react';
import { ROLE_COLOR_MAP } from '../constants';

interface SettingsModalProps {
  currentUser?: User;
  settings: UserSettings;
  hasPasswordSet: boolean;
  players?: Player[]; 
  presetFines?: PresetFine[];
  roles?: RoleDefinition[]; 
  onSave: (settings: UserSettings, newPassword?: string) => void;
  onCancel: () => void;
  onAddPlayer?: (name: string, position: string) => void;
  onRemovePlayer?: (id: string) => void;
  onAddPresetFine?: (label: string, amount: number, icon: string) => void;
  onRemovePresetFine?: (id: string) => void;
  onToggleAdmin?: (playerId: string) => void;
  onAddRole?: (name: string, color: string) => void; 
  onRemoveRole?: (id: string) => void; 
  onImportData: (data: any) => void;
  exportData: any;
}

export const SettingsModal: React.FC<SettingsModalProps> = ({ 
  currentUser, 
  settings, 
  players = [],
  presetFines = [],
  roles = [],
  onSave, 
  onCancel, 
  onAddPlayer,
  onRemovePlayer,
  onAddPresetFine,
  onRemovePresetFine,
  onAddRole,
  onRemoveRole,
  onImportData,
  exportData
}) => {
  const [phoneNumber, setPhoneNumber] = useState(settings.phoneNumber || '');
  const [email, setEmail] = useState(settings.email || '');
  const [pushEnabled, setPushEnabled] = useState(settings.pushEnabled || false);

  // Password State
  const [showPasswordSection, setShowPasswordSection] = useState(false);
  const [newPassword, setNewPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [passwordError, setPasswordError] = useState('');

  // Admin UI State
  const [newPlayerName, setNewPlayerName] = useState('');
  const [newPlayerPos, setNewPlayerPos] = useState('Spiller');
  const [showAddPlayer, setShowAddPlayer] = useState(false);
  const [playerSearch, setPlayerSearch] = useState('');
  const [showManagePlayers, setShowManagePlayers] = useState(false);

  const [newFineLabel, setNewFineLabel] = useState('');
  const [newFineAmount, setNewFineAmount] = useState('');
  const [newFineIcon, setNewFineIcon] = useState('💸');
  const [showAddFine, setShowAddFine] = useState(false);
  const [showManageFines, setShowManageFines] = useState(false);

  // Role UI State
  const [showAddRole, setShowAddRole] = useState(false);
  const [showManageRoles, setShowManageRoles] = useState(false);
  const [newRoleName, setNewRoleName] = useState('');
  const [newRoleColor, setNewRoleColor] = useState('blue');

  // Sync UI State
  const [importCode, setImportCode] = useState('');
  const [showSyncSection, setShowSyncSection] = useState(false);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    // Check password if changed
    let passToSave: string | undefined = undefined;
    if (showPasswordSection && newPassword) {
        if (newPassword !== confirmPassword) {
            setPasswordError('Passordene er ikke like');
            return;
        }
        if (newPassword.length < 4) {
            setPasswordError('Passordet må være minst 4 tegn');
            return;
        }
        passToSave = newPassword;
    }

    onSave({ ...settings, phoneNumber, email, pushEnabled }, passToSave);
  };

  const handleTogglePush = async () => {
    if (!pushEnabled) {
        if ("Notification" in window) {
            const permission = await Notification.requestPermission();
            if (permission === 'granted') {
                setPushEnabled(true);
                new Notification("NHHI FC Varsler", { body: "Push-varsler er nå aktivert!" });
            }
        }
    } else {
        setPushEnabled(false);
    }
  };

  const handleAddPlayerSubmit = () => {
      if (newPlayerName.trim() && onAddPlayer) {
          onAddPlayer(newPlayerName, newPlayerPos);
          setNewPlayerName('');
          setShowAddPlayer(false);
      }
  };

  const handleAddFineSubmit = () => {
    if (newFineLabel.trim() && newFineAmount && onAddPresetFine) {
        onAddPresetFine(newFineLabel, Number(newFineAmount), newFineIcon);
        setNewFineLabel('');
        setNewFineAmount('');
        setShowAddFine(false);
    }
  };

  const handleAddRoleSubmit = () => {
      if (newRoleName.trim() && onAddRole) {
          onAddRole(newRoleName, newRoleColor);
          setNewRoleName('');
          setNewRoleColor('blue');
          setShowAddRole(false);
      }
  };

  const handleExportCode = () => {
      try {
          const json = JSON.stringify(exportData);
          const base64 = btoa(unescape(encodeURIComponent(json)));
          const textarea = document.createElement('textarea');
          textarea.value = base64;
          document.body.appendChild(textarea);
          textarea.select();
          document.execCommand('copy');
          document.body.removeChild(textarea);
          alert("Sync-kode kopiert!");
      } catch (e) {
          alert("Feil ved generering av kode.");
      }
  };

  const handleImportSubmit = () => {
      if (!importCode.trim()) return;
      try {
          const json = decodeURIComponent(escape(atob(importCode.trim())));
          const data = JSON.parse(json);
          onImportData(data);
          alert("Data importert!");
      } catch (e) {
          alert("Ugyldig Sync-kode.");
      }
  };

  const filteredPlayers = players.filter(p => p.name.toLowerCase().includes(playerSearch.toLowerCase()));

  const resetAdminViews = () => {
      setShowAddPlayer(false);
      setShowManagePlayers(false);
      setShowAddFine(false);
      setShowManageFines(false);
      setShowAddRole(false);
      setShowManageRoles(false);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
      <div 
        className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm transition-opacity"
        onClick={onCancel}
      ></div>

      <div className="relative bg-white rounded-2xl shadow-xl w-full max-w-sm max-h-[90vh] overflow-y-auto animate-in fade-in zoom-in duration-200">
        <div className="bg-slate-50 px-6 py-4 border-b border-slate-100 flex justify-between items-center sticky top-0 z-10">
          <h3 className="font-bold text-slate-900">Innstillinger</h3>
          <button onClick={onCancel} className="text-slate-400 hover:text-slate-600">
            <X size={24} />
          </button>
        </div>

        <div className="p-6 space-y-6">
            <form onSubmit={handleSubmit} className="space-y-6">
                <div className="space-y-4">
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Profilinnstillinger</h4>

                    <div className="space-y-2">
                        <label className="block text-sm font-medium text-slate-700">Telefonnummer</label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                <Smartphone className="h-4 w-4 text-gray-400" />
                            </div>
                            <input 
                                type="tel"
                                value={phoneNumber}
                                onChange={(e) => setPhoneNumber(e.target.value)}
                                placeholder="912 34 567"
                                className="block w-full pl-9 py-2.5 text-sm border border-slate-300 rounded-xl bg-white text-slate-900"
                            />
                        </div>
                    </div>

                    <div className="space-y-2">
                        <label className="block text-sm font-medium text-slate-700">E-post</label>
                        <div className="relative">
                            <div className="absolute inset-y-0 left-0 pl-3 flex items-center pointer-events-none">
                                <Mail className="h-4 w-4 text-gray-400" />
                            </div>
                            <input 
                                type="email"
                                value={email}
                                onChange={(e) => setEmail(e.target.value)}
                                placeholder="din.epost@eksempel.no"
                                className="block w-full pl-9 py-2.5 text-sm border border-slate-300 rounded-xl bg-white text-slate-900"
                            />
                        </div>
                    </div>

                    <div className="flex items-center justify-between p-3 bg-slate-50 rounded-xl border border-slate-100">
                        <div className="flex items-center">
                            <div className={`p-2 rounded-full mr-3 ${pushEnabled ? 'bg-green-100 text-green-600' : 'bg-slate-200 text-slate-500'}`}>
                                {pushEnabled ? <Bell size={18} /> : <BellOff size={18} />}
                            </div>
                            <div>
                                <p className="font-semibold text-sm text-slate-900">Varsler</p>
                                <p className="text-[10px] text-slate-500">Push-meldinger</p>
                            </div>
                        </div>
                        <button
                            type="button"
                            onClick={handleTogglePush}
                            className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${pushEnabled ? 'bg-blue-600' : 'bg-gray-200'}`}
                        >
                            <span
                                className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${pushEnabled ? 'translate-x-6' : 'translate-x-1'}`}
                            />
                        </button>
                    </div>
                </div>

                <hr className="border-slate-100" />

                <div className="space-y-4">
                    <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Sikkerhet</h4>
                    {!showPasswordSection ? (
                         <button 
                            type="button"
                            onClick={() => setShowPasswordSection(true)}
                            className="w-full flex items-center justify-between p-3 bg-white border border-slate-200 rounded-xl hover:bg-slate-50 transition-colors"
                        >
                            <div className="flex items-center">
                                <Lock size={18} className="text-slate-400 mr-3" />
                                <span className="text-sm font-medium text-slate-700">Endre Passord</span>
                            </div>
                        </button>
                    ) : (
                        <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 space-y-3 animate-in fade-in slide-in-from-top-2">
                             <div className="space-y-2">
                                <label className="block text-xs font-bold text-slate-500 uppercase">Nytt Passord</label>
                                <div className="relative">
                                    <KeyRound size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        type="password" 
                                        value={newPassword}
                                        onChange={(e) => {
                                            setNewPassword(e.target.value);
                                            setPasswordError('');
                                        }}
                                        className="w-full pl-9 p-2.5 text-sm border border-slate-300 rounded-lg"
                                        placeholder="Minst 4 tegn"
                                    />
                                </div>
                             </div>
                             <div className="space-y-2">
                                <label className="block text-xs font-bold text-slate-500 uppercase">Bekreft Passord</label>
                                <div className="relative">
                                    <KeyRound size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                                    <input 
                                        type="password" 
                                        value={confirmPassword}
                                        onChange={(e) => {
                                            setConfirmPassword(e.target.value);
                                            setPasswordError('');
                                        }}
                                        className="w-full pl-9 p-2.5 text-sm border border-slate-300 rounded-lg"
                                        placeholder="Gjenta passord"
                                    />
                                </div>
                             </div>
                             {passwordError && (
                                 <p className="text-xs text-red-600 font-medium flex items-center">
                                     <AlertCircle size={12} className="mr-1"/> {passwordError}
                                 </p>
                             )}
                             <button type="button" onClick={() => {setShowPasswordSection(false); setNewPassword(''); setConfirmPassword('');}} className="text-[10px] text-slate-400 underline w-full">Avbryt</button>
                        </div>
                    )}
                </div>

                <Button type="submit" fullWidth>Lagre Endringer</Button>
            </form>

            <hr className="border-slate-100" />

            <div className="space-y-4">
                <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Backup</h4>
                {!showSyncSection ? (
                    <button 
                        onClick={() => setShowSyncSection(true)}
                        className="w-full flex items-center justify-between p-3 bg-white border border-slate-200 rounded-xl hover:bg-slate-50 transition-colors"
                    >
                        <div className="flex items-center">
                            <Copy size={18} className="text-slate-400 mr-3" />
                            <span className="text-sm font-medium text-slate-700">Eksport/Import</span>
                        </div>
                    </button>
                ) : (
                    <div className="space-y-4 bg-slate-50 p-4 rounded-xl border border-slate-100 animate-in fade-in slide-in-from-top-2">
                        <button 
                            onClick={handleExportCode}
                            className="w-full py-2 bg-blue-600 text-white rounded-lg text-xs font-bold"
                        >
                            <Download size={14} className="inline mr-2" /> Eksportér
                        </button>
                        <div className="space-y-2">
                            <textarea 
                                value={importCode}
                                onChange={(e) => setImportCode(e.target.value)}
                                className="w-full p-2 text-[10px] font-mono border border-slate-300 rounded-lg h-16"
                                placeholder="Lim inn kode her..."
                            />
                            <button 
                                onClick={handleImportSubmit}
                                className="w-full py-2 bg-slate-800 text-white rounded-lg text-xs font-bold"
                            >
                                <Upload size={14} className="inline mr-2" /> Importér
                            </button>
                        </div>
                        <button onClick={() => setShowSyncSection(false)} className="text-[10px] text-slate-400 underline w-full">Lukk</button>
                    </div>
                )}
            </div>

            {currentUser?.role === 'admin' && (
                <>
                    <hr className="border-slate-100" />
                    <div className="space-y-4 pb-4">
                        <h4 className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Admin Verktøy</h4>

                        {!showAddPlayer && !showManagePlayers && !showAddFine && !showManageFines && !showAddRole && !showManageRoles ? (
                            <div className="grid grid-cols-2 gap-3">
                                <button onClick={() => setShowAddPlayer(true)} className="p-3 bg-blue-50 border border-blue-100 rounded-xl flex flex-col items-center">
                                    <BadgePlus size={20} className="mb-1 text-blue-600" />
                                    <span className="text-[10px] font-black uppercase">Ny Spiller</span>
                                </button>
                                <button onClick={() => setShowManagePlayers(true)} className="p-3 bg-slate-50 border border-slate-200 rounded-xl flex flex-col items-center">
                                    <Trash2 size={20} className="mb-1 text-slate-600" />
                                    <span className="text-[10px] font-black uppercase">Fjern Spiller</span>
                                </button>
                            </div>
                        ) : (
                            <div className="bg-slate-50 p-4 rounded-xl border border-slate-100 space-y-4 animate-in fade-in slide-in-from-top-2">
                                {showAddPlayer && (
                                    <div className="space-y-3">
                                        <input 
                                            type="text" 
                                            value={newPlayerName}
                                            onChange={(e) => setNewPlayerName(e.target.value)}
                                            className="w-full p-2.5 text-sm border border-slate-300 rounded-lg"
                                            placeholder="Navn"
                                        />
                                        <Button fullWidth onClick={handleAddPlayerSubmit}>Opprett</Button>
                                    </div>
                                )}
                                {showManagePlayers && (
                                    <div className="space-y-1 max-h-40 overflow-y-auto">
                                        {filteredPlayers.map(p => (
                                            <div key={p.id} className="flex justify-between items-center bg-white p-2 rounded border border-slate-100">
                                                <span className="text-xs font-bold">{p.name}</span>
                                                <button onClick={() => onRemovePlayer?.(p.id)} className="text-red-500"><Trash2 size={14}/></button>
                                            </div>
                                        ))}
                                    </div>
                                )}
                                <button onClick={resetAdminViews} className="text-[10px] text-slate-400 underline w-full">Tilbake</button>
                            </div>
                        )}
                    </div>
                </>
            )}
        </div>
      </div>
    </div>
  );
};
